const FRESH_MS = 15000;
const ZERO_OFF_MS = 60000;
const AUTOMATION_COUNT_SOURCE = 'total-count';
const CONTROLLED = [2,3,4,6,7,8];
const TOPICS = {2:'lab/control/relay2/set',3:'lab/control/relay3/set',4:'lab/control/relay4/set',6:'lab/control/relay6/set',7:'lab/control/relay7/set',8:'lab/control/relay8/set'};
function m(topic,payload,retain=false){return {topic,payload:typeof payload==='string'?payload:JSON.stringify(payload),retain};}
function send(commands,diagnostics){node.send([commands.length?commands:null,diagnostics.length?diagnostics:null]);}
function desired(stage){const s={2:'OFF',3:'OFF',4:'OFF',6:'OFF',7:'OFF',8:'OFF'};if(stage==='LOW_STAGE'){s[2]='ON';s[3]='ON';s[6]='ON';s[7]='ON';}else if(stage==='HIGH_STAGE'){for(const relay of Object.keys(s))s[relay]='ON';}return s;}
function healthy(now){const lastHeartbeat=context.get('lastHeartbeat')||0;const lastCount=context.get('lastCountTs')||0;return context.get('serviceOnline')===true&&context.get('sourceHealthy')===true&&lastHeartbeat>0&&lastCount>0&&(now-lastHeartbeat)<=FRESH_MS&&(now-lastCount)<=FRESH_MS;}
function actual(){return context.get('actual')||{};}
function correctionFeedback(){return context.get('correctionFeedback')||{};}
function manualOverrides(){return context.get('manualOverrides')||{};}
function hasManualOverrides(){return Object.keys(manualOverrides()).length > 0;}
function applyOverrides(wanted){if((context.get('mode')||'manual')!=='manual')return Object.assign({},wanted);const merged=Object.assign({},wanted);for(const [relay,state] of Object.entries(manualOverrides()))merged[relay]=state;return merged;}
function setManualOverride(relay,state){const overrides=manualOverrides();overrides[String(relay)]=state;context.set('manualOverrides',overrides);}
function clearManualOverride(payload){if(payload===undefined||payload===null||String(payload).toLowerCase()==='all'){context.set('manualOverrides',{});return 'cleared all manual overrides';}const overrides=manualOverrides();if(Array.isArray(payload)){for(const relay of payload)delete overrides[String(relay)];}else{delete overrides[String(payload)];}context.set('manualOverrides',overrides);return 'cleared requested manual override(s)';}
function commandsFor(wanted){const a=actual(),seen=correctionFeedback(),commands=[];for(const [relay,state] of Object.entries(wanted)){const feedback=(a[relay]===undefined||a[relay]===null)?'UNKNOWN':a[relay];if(a[relay]!==state&&seen[relay]!==feedback){commands.push(m(TOPICS[relay],state,false));seen[relay]=feedback;}}context.set('correctionFeedback',seen);return commands;}
function stageForStableCount(count){if(count<=0)return 'EMPTY_STAGE';if(count>=4)return 'HIGH_STAGE';return context.get('highLoadLatch')===true?'HIGH_STAGE':'LOW_STAGE';}
function stalePreserveTarget(reason){const base=Object.assign({},context.get('lastKnownAutomation')||actual());return {decisionSource:'VISION_STALE',stage:'VISION_STALE',wanted:applyOverrides(base),commands:[],reason};}
function automationTarget(count,now){let stage;if(count===0){let zeroSince=context.get('zeroSince')||0;if(!zeroSince){zeroSince=now;context.set('zeroSince',zeroSince);}if((now-zeroSince)<ZERO_OFF_MS){return {decisionSource:'PEOPLE_COUNT',stage:'ZERO_HOLD',wanted:applyOverrides(context.get('lastKnownAutomation')||desired(context.get('activeStage')||'EMPTY_STAGE')),reason:'healthy zero hold'};}context.set('highLoadLatch',false);stage='EMPTY_STAGE';}else{context.set('zeroSince',0);if(count>=4)context.set('highLoadLatch',true);stage=stageForStableCount(count);}const base=desired(stage);context.set('activeStage',stage);context.set('lastKnownAutomation',Object.assign({},base));context.set('lastApply',now);return {decisionSource:'PEOPLE_COUNT',stage,wanted:applyOverrides(base),reason:`applied ${stage}`};}
function relayReconnectTarget(now){const count=context.get('latestCount');if((context.get('mode')||'manual')!=='auto'||!healthy(now)||!Number.isInteger(count)){return {stage:'RELAY_ONLINE_NO_RESYNC',wanted:{},commands:[],reason:'relay online; no Auto resync required'};}const target=automationTarget(count,now);const commands=target.stage==='ZERO_HOLD'?[]:commandsFor(target.wanted);return Object.assign({},target,{commands,reason:'relay controller reconnected -> resync desired Auto state'});}
function reconcileTarget(now){const count=context.get('latestCount');if((context.get('mode')||'manual')!=='auto'||!healthy(now)||!Number.isInteger(count)){return {stage:'RECONCILE_SKIPPED',wanted:{},commands:[],reason:'periodic relay reconciliation skipped'};}const target=automationTarget(count,now);const commands=target.stage==='ZERO_HOLD'?[]:commandsFor(target.wanted);return Object.assign({},target,{commands,reason:`periodic relay feedback reconciliation: ${target.reason}`});}
function publishState(diags){diags.push(m('lab/automation/status','online',true));diags.push(m('lab/automation/mode_state',context.get('mode')||'manual',true));diags.push(m('lab/automation/count_source',AUTOMATION_COUNT_SOURCE,true));diags.push(m('lab/automation/manual_override_state',manualOverrides(),true));diags.push(m('lab/automation/high_load_latch',context.get('highLoadLatch')===true?'active':'inactive',true));const isHealthy=healthy(now);diags.push(m('lab/automation/vision_health',isHealthy?'healthy':'stale',true));diags.push(m('lab/automation/warning',isHealthy?'none':'vision unhealthy -> preserving relay state',true));const lastCount=context.get('lastCountTs')||0;diags.push(m('lab/automation/vision_age_seconds',lastCount?Math.floor((now-lastCount)/1000):-1,true));}
const topic=String(msg.topic||'');
const now=Date.now();
let diagnostics=[];
if(topic==='lab/automation/mode'){
  const next=String(msg.payload).trim().toLowerCase();
  const value=['manual','monitor','auto'].includes(next)?next:'manual';
  context.set('mode',value);
  if(value!=='auto')context.set('zeroSince',0);else context.set('correctionFeedback',{});
  diagnostics.push(m('lab/automation/status','online',true));
  diagnostics.push(m('lab/automation/mode_state',value,true));
  diagnostics.push(m('lab/automation/count_source',AUTOMATION_COUNT_SOURCE,true));
  diagnostics.push(m('lab/automation/last_action',`mode set to ${value}`,true));
  if(value==='auto'){
    const count=context.get('latestCount');
    const target=(healthy(now)&&Number.isInteger(count))?automationTarget(count,now):stalePreserveTarget('vision unhealthy -> preserving relay state');
    diagnostics.push(m('lab/automation/priority_state',target.decisionSource,true));
    diagnostics.push(m('lab/automation/intended_state',{publisher:'nodered-lab-priority',stage:target.stage,count,relays:target.wanted,high_load_latch:context.get('highLoadLatch')===true,reason:target.reason,decision_source:target.decisionSource,count_source:AUTOMATION_COUNT_SOURCE,timestamp:Math.floor(now/1000)},true));
    diagnostics.push(m('lab/automation/warning',healthy(now)?'none':target.reason,true));
    const commands=(target.stage==='ZERO_HOLD'||target.decisionSource!=='PEOPLE_COUNT')?[]:commandsFor(target.wanted);
    send(commands,diagnostics);
    return null;
  }
  diagnostics.push(m('lab/automation/priority_state',value==='manual'?(hasManualOverrides()?'MANUAL_OVERRIDE':'MANUAL'):'MONITOR',true));
  diagnostics.push(m('lab/automation/warning','none',true));
  send([],diagnostics);
  return null;
}
if(topic==='lab/automation/manual_override/clear'){
  diagnostics.push(m('lab/automation/last_action',clearManualOverride(msg.payload),true));
  diagnostics.push(m('lab/automation/manual_override_state',manualOverrides(),true));
  diagnostics.push(m('lab/automation/priority_state',(context.get('mode')||'manual')==='manual'?'MANUAL':((context.get('mode')||'manual')==='monitor'?'MONITOR':(healthy(now)?'PEOPLE_COUNT':'VISION_STALE')),true));
  diagnostics.push(m('lab/automation/warning',healthy(now)?'none':'vision unhealthy -> preserving relay state',true));
  send([],diagnostics);
  return null;
}
if(topic==='lab/vision/status'){
  let value=String(msg.payload).toLowerCase();
  try{const parsed=typeof msg.payload==='object'?msg.payload:JSON.parse(String(msg.payload));value=String(parsed.status||value).toLowerCase();}catch(e){}
  context.set('serviceOnline',value==='online'||value==='healthy');
  return null;
}
if(topic==='lab/vision/source_status'){
  context.set('sourceHealthy',String(msg.payload).toLowerCase()==='healthy');
  return null;
}
if(topic==='lab/vision/heartbeat'){
  context.set('lastHeartbeat',now);
  return null;
}
if(topic==='lab/control/status'){
  const online=String(msg.payload).toLowerCase()==='online';
  const wasOnline=context.get('relayOnline')===true;
  context.set('relayOnline',online);
  if(!online){
    context.set('actual',{});
    context.set('correctionFeedback',{});
    context.set('relayResyncNeeded',true);
    diagnostics.push(m('lab/automation/relay_status','offline',true));
    diagnostics.push(m('lab/automation/last_action','relay controller offline -> cleared known relay feedback',true));
    send([],diagnostics);
    return null;
  }
  diagnostics.push(m('lab/automation/relay_status','online',true));
  if(!wasOnline&&context.get('relayResyncNeeded')===true){
    const target=relayReconnectTarget(now);
    diagnostics.push(m('lab/automation/last_action',target.reason,true));
    diagnostics.push(m('lab/automation/intended_state',{publisher:'nodered-lab-priority',stage:target.stage,count:context.get('latestCount'),relays:target.wanted,high_load_latch:context.get('highLoadLatch')===true,reason:target.reason,decision_source:healthy(now)?'PEOPLE_COUNT':'VISION_STALE',count_source:AUTOMATION_COUNT_SOURCE,timestamp:Math.floor(now/1000)},true));
    context.set('relayResyncNeeded',false);
    send(target.commands,diagnostics);
    return null;
  }
  send([],diagnostics);
  return null;
}
const stateMatch=topic.match(/^lab\/control\/relay(\d+)\/state$/);
if(stateMatch){
  const relay=stateMatch[1];
  const state=String(msg.payload).toUpperCase();
  const a=actual();
  a[relay]=state;
  context.set('actual',a);
  if((context.get('mode')||'manual')==='manual')setManualOverride(relay,state);
  return null;
}
if(topic==='lab/automation/internal/tick'){
  publishState(diagnostics);
  if((context.get('mode')||'manual')==='manual'){
    diagnostics.push(m('lab/automation/priority_state',hasManualOverrides()?'MANUAL_OVERRIDE':'MANUAL',true));
    send([],diagnostics);
    return null;
  }
  if((context.get('mode')||'manual')==='monitor')diagnostics.push(m('lab/automation/priority_state',healthy(now)?'PEOPLE_COUNT':'VISION_STALE',true));
  if(!healthy(now)){
    const fb=stalePreserveTarget('vision unhealthy -> preserving relay state');
    diagnostics.push(m('lab/automation/priority_state',fb.decisionSource,true));
    diagnostics.push(m('lab/automation/warning',fb.reason,false));
    send([],diagnostics);
    return null;
  }
  if((context.get('mode')||'manual')==='auto'){
    const target=reconcileTarget(now);
    diagnostics.push(m('lab/automation/intended_state',{publisher:'nodered-lab-priority',stage:target.stage,count:context.get('latestCount'),relays:target.wanted,high_load_latch:context.get('highLoadLatch')===true,reason:target.reason,decision_source:'PEOPLE_COUNT',count_source:AUTOMATION_COUNT_SOURCE,timestamp:Math.floor(now/1000)},true));
    send(target.commands,diagnostics);
    return null;
  }
  send([],diagnostics);
  return null;
}
if(topic!=='lab/vision/people_count') return null;
let payload=msg.payload;
if(Buffer.isBuffer(payload))payload=payload.toString();
if(typeof payload==='string'){try{payload=JSON.parse(payload);}catch(e){diagnostics.push(m('lab/automation/warning','invalid people_count payload ignored',false));send([],diagnostics);return null;}}
let ts=Number(payload&&payload.timestamp||0); if(ts<100000000000) ts*=1000;
const count=Number(payload&&payload.stable_count);
const valid=payload&&payload.source_healthy===true&&payload.status==='online'&&Number.isInteger(count)&&count>=0&&Math.abs(now-ts)<=FRESH_MS;
if(valid){context.set('latestCount',count);context.set('lastCountTs',now);context.set('serviceOnline',true);context.set('sourceHealthy',true);}publishState(diagnostics);
if(!valid){const fb=stalePreserveTarget('vision unhealthy -> preserving relay state');diagnostics.push(m('lab/automation/warning',fb.reason,false));diagnostics.push(m('lab/automation/priority_state',fb.decisionSource,true));send([],diagnostics);return null;}
if((context.get('mode')||'manual')==='manual'){
  diagnostics.push(m('lab/automation/accepted_count',{publisher:'nodered-lab-priority',count,target:'MANUAL_PRESERVE',count_source:AUTOMATION_COUNT_SOURCE,timestamp:Math.floor(now/1000)},false));
  diagnostics.push(m('lab/automation/priority_state',hasManualOverrides()?'MANUAL_OVERRIDE':'MANUAL',true));
  send([],diagnostics);
  return null;
}
const target=automationTarget(count,now);
diagnostics.push(m('lab/automation/accepted_count',{publisher:'nodered-lab-priority',count,target:target.stage,count_source:AUTOMATION_COUNT_SOURCE,timestamp:Math.floor(now/1000)},false));
diagnostics.push(m('lab/automation/priority_state',target.decisionSource,true));
diagnostics.push(m('lab/automation/intended_state',{publisher:'nodered-lab-priority',stage:target.stage,count,relays:target.wanted,high_load_latch:context.get('highLoadLatch')===true,reason:target.reason,decision_source:target.decisionSource,count_source:AUTOMATION_COUNT_SOURCE,timestamp:Math.floor(now/1000)},true));
if((context.get('mode')||'manual')==='monitor'){
  send([],diagnostics);
  return null;
}
const commands=target.stage==='ZERO_HOLD'?[]:commandsFor(target.wanted);
send(commands,diagnostics);
return null;
